class Solution:
    def power(self, a: int, b: int) -> int:
        if b == 0:
            return 1
        if b == 1:
            return a
        temp = self.power(a, b // 2)
        if b % 2 == 0:
            return temp * temp
        else:
            return a * temp * temp

    def main(self):
        a, b = map(int, input().split())
        print(self.power(a, b))

if __name__ == '__main__':
    obj = Solution()
    obj.main()

solutions.cpp:
class Solution {
public:
    long long power(long long a, long long b) {
        if (b == 0) return 1;
        if (b == 1) return a;
        long long temp = power(a, b / 2);
        if (b % 2 == 0) return temp * temp;
        else return a * temp * temp;
    }
};

int main() {
    Solution solver;
    long long a, b;
    cin >> a >> b;
    cout << solver.power(a, b) << endl;
    return 0;
}
